",paraId:5},{value:"// 方式一\ngraph.startBatch('custom-batch-name')\n// 节点改变边框颜色以及修改位置会合并成一条记录，可以一次性撤销\nnode.attr('body/stroke', 'red')\nnode.position(30, 30)\ngraph.stopBatch('custom-batch-name')\n\n// 方式二\ngraph.batchUpdate(() => {\n  node.prop('zIndex', 10)\n  node.attr('label/text', 'hello')\n  node.attr('label/fill', '#ff0000')\n})\n",paraId:6},{value:"undo(options?: KeyValue): this\n",paraId:7,tocIndex:4},{value:"撤销。",paraId:8,tocIndex:4},{value:"options",paraId:8,tocIndex:4},{value:" 将被传递到事件回调中。",paraId:8,tocIndex:4},{value:"undoAndCancel(options?: KeyValue): this\n",paraId:9,tocIndex:5},{value:"撤销，并且不添加到重做队列中，因此该命令不能被重做。",paraId:10,tocIndex:5},{value:"options",paraId:10,tocIndex:5},{value:" 将被传递到事件回调中。",paraId:10,tocIndex:5},{value:"redo(options?: KeyValue): this\n",paraId:11,tocIndex:6},{value:"重做。",paraId:12,tocIndex:6},{value:"options",paraId:12,tocIndex:6},{value:" 将被传递到事件回调中。",paraId:12,tocIndex:6},{value:"canUndo(): boolean\n",paraId:13,tocIndex:7},{value:"是否可以撤销。",paraId:14,tocIndex:7},{value:"canRedo(): boolean\n",paraId:15,tocIndex:8},{value:"是否可以重做。",paraId:16,tocIndex:8},{value:"cleanHistory(options?: KeyValue): this\n",paraId:17,tocIndex:9},{value:"清空历史队列。",paraId:18,tocIndex:9},{value:"options",paraId:18,tocIndex:9},{value:" 将被传递到事件回调中。",paraId:18,tocIndex:9},{value:"getHistoryStackSize(): number\n",paraId:19,tocIndex:10},{value:"获取 history 栈的尺寸。",paraId:20,tocIndex:10},{value:"getUndoRemainSize(): number\n",paraId:21,tocIndex:11},{value:"获取 history undo 栈的剩余尺寸。",paraId:22,tocIndex:11},{value:"getUndoStackSize(): number\n",paraId:23,tocIndex:12},{value:"获取 history undo 栈的尺寸。",paraId:24,tocIndex:12},{value:"getRedoStackSize(): number\n",paraId:25,tocIndex:13},{value:"获取 history redo 栈的尺寸。",paraId:26,tocIndex:13},{value:"isHistoryEnabled(): boolean\n",paraId:27,tocIndex:14},{value:"返回是否启用了历史状态。",paraId:28,tocIndex:14},{value:"enableHistory(): this\n",paraId:29,tocIndex:15},{value:"启用历史状态。",paraId:30,tocIndex:15},{value:"disableHistory(): this\n",par